import type React from 'react';
import type { UseFormListProps, UseFormListReturnValue } from './internal/useFormList';
import { useFormList } from './internal/useFormList';

export type FormListProps<FieldValue> = UseFormListProps & {
  /**
   * 表单列表的子元素渲染函数
   */
  children: (formListInfo: UseFormListReturnValue<FieldValue>) => React.ReactElement | null;
};

export function FormList<FieldValue>(props: FormListProps<FieldValue>): React.ReactElement | null {
  const { children, ...options } = props;
  const info = useFormList({
    ...options,
  });
  return children?.(info);
}
